--
-- Table structure for table `movimientos`
--

DROP TABLE IF EXISTS `movimientos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `movimientos` (
  `fecha_hora` datetime NOT NULL,
  `pedido_id_pedido` varchar(8) COLLATE utf8mb4_unicode_ci NOT NULL,
  `estado_inicial_id` int unsigned NOT NULL,
  `estado_final_id` int unsigned NOT NULL,
  `usuario_id` int unsigned NOT NULL,
  `motivo_anulacion` varchar(250) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`pedido_id_pedido`,`estado_final_id`),
  KEY `movimientos_estado_inicial_id_index` (`estado_inicial_id`),
  KEY `movimientos_estado_final_id_index` (`estado_final_id`),
  KEY `movimientos_usuario_id_index` (`usuario_id`),
  KEY `idx_movimientos_fecha_hora` (`fecha_hora`),
  CONSTRAINT `movimientos_estado_final_id_foreign` FOREIGN KEY (`estado_final_id`) REFERENCES `tipos_estado` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `movimientos_estado_inicial_id_foreign` FOREIGN KEY (`estado_inicial_id`) REFERENCES `tipos_estado` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `movimientos_pedido_id_pedido_foreign` FOREIGN KEY (`pedido_id_pedido`) REFERENCES `pedidos` (`id_pedido`) ON UPDATE CASCADE,
  CONSTRAINT `movimientos_usuario_id_foreign` FOREIGN KEY (`usuario_id`) REFERENCES `usuarios` (`id`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

